31→/**
32→ * Distribute by custom tier percentages.
33→ * tiers = [40, 25, 15, 20] means rank1=40%, rank2=25%, rank3=15%, rest split 20%.
34→ * If tiers is null/empty, falls back to inverse-rank proportional.
35→ */
36→export function computeLeaderboard(
37→    totalAmount: bigint,
38→    participants: Participant[],
39→    tiers?: number[] | null,
40→): PayoutResult[] {
41→    if (participants.length === 0) return [];
42→    if (tiers && tiers.length > 0) {
43→        return computeLeaderboardTiers(totalAmount, participants, tiers);
44→    }
45→    return computeLeaderboardProportional(totalAmount, participants);
