48→function computeLeaderboardTiers(
49→    totalAmount: bigint,
50→    participants: Participant[],
51→    tiers: number[],
52→): PayoutResult[] {
53→    const results: PayoutResult[] = [];
54→    let distributed = 0n;
55→
56→    for (let i = 0; i < participants.length; i++) {
57→        let amount: bigint;
58→
59→        if (i < tiers.length - 1) {
60→            // Named tier: exact percentage
61→            amount = (totalAmount * BigInt(tiers[i])) / 100n;
62→        } else if (tiers.length > 0 && participants.length > tiers.length - 1) {
63→            // "Rest" bucket: last tier % split among remaining participants
64→            const restPercent = tiers[tiers.length - 1];
65→            const restPool = (totalAmount * BigInt(restPercent)) / 100n;
66→            const restCount = participants.length - (tiers.length - 1);
67→            amount = restPool / BigInt(restCount);
68→        } else {
69→            amount = 0n;
70→        }
71→
72→        distributed += amount;
73→        results.push({
74→            participantId: participants[i].id,
75→            agentId: participants[i].agentId,
76→            wallet: participants[i].wallet,
77→            amount,
78→        });
79→    }
