 12→/**
 13→ * Create a Stripe Checkout Session for quest funding.
 14→ * Sponsor clicks "Pay with Card" → redirect to Stripe hosted page → pays → webhook confirms.
 15→ */
 16→export async function createFundCheckout(
 17→    prisma: PrismaClient,
 18→    questId: string,
 19→    successUrl: string,
 20→    cancelUrl: string,
 21→): Promise<{ checkoutUrl: string; sessionId: string }> {
 22→    const quest = await prisma.quest.findUnique({ where: { id: questId } });
 23→    if (!quest) throw new Error('Quest not found');
 24→    if (quest.fundingStatus === 'confirmed') throw new Error('Quest already funded');
 25→
 26→    // Stripe uses smallest currency unit (cents for USD)
 27→    const amountCents = Number(quest.rewardAmount) * 100;
 28→
 29→    const session = await stripe.checkout.sessions.create({
 30→        mode: 'payment',
 31→        payment_method_types: ['card'],
 32→        line_items: [{
 33→            price_data: {
 34→                currency: stripeConfig.currency,
 35→                unit_amount: amountCents,
 36→                product_data: {
 37→                    name: `Fund Quest: ${quest.title}`,
 38→                    description: `Reward pool for "${quest.title}" (${quest.type}, ${quest.totalSlots} slots)`,
 39→                    metadata: { questId },
 40→                },
 41→            },
 42→            quantity: 1,
 43→        }],
 44→        metadata: {
 45→            questId,
 46→            type: 'quest_funding',
 47→        },
 48→        success_url: successUrl,
 49→        cancel_url: cancelUrl,
 50→    });
 51→
 52→    // Persist session → quest link
 53→    await prisma.quest.update({
 54→        where: { id: questId },
 55→        data: {
 56→            stripeSessionId: session.id,
 57→            fundingMethod: 'stripe',
 58→            fundingStatus: 'pending',
 59→        },
 60→    });
 61→
 62→    return { checkoutUrl: session.url!, sessionId: session.id };
 63→}
