 31→// ─── Regex patterns for task param validation ────────────────────────────────
 32→export const X_POST_URL_RE = /^https?:\/\/(x\.com|twitter\.com)\/\w+\/status\/\d+/i;
 33→export const X_USERNAME_RE = /^@?[\w]{1,15}$/;
 34→export const DISCORD_INVITE_RE = /^https?:\/\/(discord\.gg|discord\.com\/invite)\/[\w-]+$/i;
 35→export const TELEGRAM_CHANNEL_RE = /^(@[\w]{5,32}|https?:\/\/t\.me\/[\w]+)$/i;
 36→
 37→/** Validate task params based on platform + actionType. Returns error string or null. */
 38→export function validateTaskParams(task: QuestTask): string | null {
 39→    const p = task.params;
 40→    switch (task.actionType) {
 41→        case 'follow_account':
 42→            if (!p.username || !X_USERNAME_RE.test(p.username))
 43→                return `Task "${task.label}": invalid X username "${p.username || ''}"`;
 44→            break;
 45→        case 'like_post':
 46→        case 'repost':
 47→        case 'quote_post':
 48→            if (!p.postUrl || !X_POST_URL_RE.test(p.postUrl))
 49→                return `Task "${task.label}": invalid X post URL "${p.postUrl || ''}"`;
 50→            break;
 51→        case 'post':
 52→            if (!p.content || p.content.length > 280)
 53→                return `Task "${task.label}": post content required (max 280 chars)`;
 54→            break;
 55→        case 'join_server':
 56→            if (!p.inviteUrl || !DISCORD_INVITE_RE.test(p.inviteUrl))
 57→                return `Task "${task.label}": invalid Discord invite URL "${p.inviteUrl || ''}"`;
 58→            break;
 59→        case 'verify_role':
 60→            if (!p.inviteUrl || !DISCORD_INVITE_RE.test(p.inviteUrl))
 61→                return `Task "${task.label}": invalid Discord invite URL "${p.inviteUrl || ''}"`;
 62→            if (!p.roleId)
 63→                return `Task "${task.label}": role ID is required`;
 64→            if (!p.roleName)
 65→                return `Task "${task.label}": role name is required`;
 66→            break;
 67→        case 'join_channel':
 68→            if (!p.channelUrl || !TELEGRAM_CHANNEL_RE.test(p.channelUrl))
 69→                return `Task "${task.label}": invalid Telegram channel "${p.channelUrl || ''}"`;
 70→            break;
 71→        default:
 72→            return `Task "${task.label}": unknown action type "${task.actionType}"`;
 73→    }
 74→    return null;
 75→}
 76→
 77→/** Validate all tasks in an array. Returns first error or null. */
 78→export function validateAllTasks(tasks: QuestTask[]): string | null {
 79→    for (const task of tasks) {
 80→        const err = validateTaskParams(task);
 81→        if (err) return err;
 82→    }
 83→    return null;
 84→}
