 56→// ─── Amount Conversion ───────────────────────────────────────────────────────
 57→//
 58→// On-chain amounts are in smallest unit (e.g., 1 USDC = 1_000_000, 1 ETH = 1e18).
 59→// API/DB stores human-readable amounts (e.g., 500 = 500 USDC).
 60→
 61→/**
 62→ * Convert a human-readable amount to the token's smallest unit.
 63→ * @param amount - Human-readable amount (e.g., 500 for 500 USDC)
 64→ * @param decimals - Token decimals (e.g., 6 for USDC, 18 for ETH)
 65→ * @returns Amount in smallest unit as bigint
 66→ */
 67→export function toSmallestUnit(amount: number, decimals: number): bigint {
 68→    // Use string manipulation to avoid floating point issues
 69→    const [whole, frac = ''] = amount.toString().split('.');
 70→    const fracPadded = frac.padEnd(decimals, '0').slice(0, decimals);
 71→    return BigInt(whole + fracPadded);
 72→}
 73→
 74→/**
 75→ * Convert from smallest unit to human-readable amount.
 76→ * @param amount - Amount in smallest unit (bigint or string)
 77→ * @param decimals - Token decimals
 78→ * @returns Human-readable number
 79→ */
 80→export function fromSmallestUnit(amount: bigint | string, decimals: number): number {
 81→    const amountBig = typeof amount === 'string' ? BigInt(amount) : amount;
 82→    const divisor = 10n ** BigInt(decimals);
 83→    const whole = amountBig / divisor;
 84→    const frac = amountBig % divisor;
 85→    const fracStr = frac.toString().padStart(decimals, '0');
 86→    return parseFloat(`${whole}.${fracStr}`);
 87→}
